import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"32. Redundancy And Associated Entitlements","description":"","frontmatter":{"title":"32. Redundancy And Associated Entitlements","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["wages","employment","redundancy","termination"]},"headers":[],"relativePath":"ebas/mspp/employment/32-redundancy-and-associated-entitlements.md","filePath":"ebas/mspp/employment/32-redundancy-and-associated-entitlements.md"}'),r={name:"ebas/mspp/employment/32-redundancy-and-associated-entitlements.md"};function s(i,e,p,l,d,c){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_32-redundancy-and-associated-entitlements" tabindex="-1">32. Redundancy And Associated Entitlements <a class="header-anchor" href="#_32-redundancy-and-associated-entitlements" aria-label="Permalink to &quot;32. Redundancy And Associated Entitlements&quot;">​</a></h1><p><strong>32.1</strong> Arrangement This clause is arranged as follows:</p><p><strong>a.</strong> Arrangement (subclause 32.1),</p><p><strong>b.</strong> Definitions (subclause 32.2),</p><p><strong>c.</strong> Redeployment (subclause 32.3),</p><p><strong>d.</strong> Support to Affected Employees (subclause 32.4),</p><p><strong>e.</strong> Salary maintenance (subclause 32.4b),</p><p><strong>f.</strong> Relocation (subclause 32.5);</p><p><strong>g.</strong> Employment terminates due to Redundancy (Termination) (subclause 32.6); and</p><p><strong>h.</strong> Exception to application of Victorian Government’s policy with respect to severance pay (subclause 36.7).</p><p><strong>32.2</strong> Definitions</p><p><strong>a.</strong> Affected Employee for this clause 32.2 means an Employee who is proposed to be made redundant or who as a result of a process under this clause agrees to relocate from their Base Employment Campus and that relocation to the alternative campus is in excess of a reasonable distance.</p><p><strong>b.</strong> Base Employment Campus means a Campus of the Employer at which the Employee ordinarily starts and finishes work.</p><p><strong>c.</strong> Comparable Role means an on-going role that:</p><p><strong>(i)</strong> is the same occupation as that of the Affected Employee’s redundant position or if not, is in an occupation acceptable to the Affected Employee; and</p><p><strong>(ii)</strong> is any of the following: <strong>(A)</strong> in the same professional discipline as that of the Affected Employee’s former position; <strong>(B)</strong> other professional discipline acceptable to the Affected Employee; or <strong>(C)</strong> a position that with the reasonable support described at subclause 32.3c, the Affected Employee could undertake;</p><p><strong>(iii)</strong> is the same grade as the Affected Employee’s redundant position; and</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>(iv)</strong> takes into account the number of ordinary hours and roster normally worked by the Affected Employee; and</p><p><strong>(v)</strong> is a Reasonable Distance from the Affected Employee’s current work location; and</p><p><strong>(vi)</strong> takes the Affected Employee’s personal circumstances, including family responsibilities, into account; and</p><p><strong>(vii)</strong> takes account of health and safety considerations; and</p><p><strong>(viii)</strong> the Affected Employee has the necessary skills and experience to undertake to a minimum satisfactory standard, or could do so with appropriate training/retraining; or</p><p><strong>(ix)</strong> is a comparable role and has terms and conditions that are alike to those of the Affected Employee’s current role.</p><p><strong>d.</strong> Consultation is as defined at <a href="/eba/ebas/mspp/employment/30-consultation.html">clause 30</a> (Consultation) of this Agreement.</p><p><strong>e.</strong> Continuity of Service for the purposes of this subclause (including subclause</p><p><strong>32.7</strong> (a) (ii)) means that the service of the Employee is treated as unbroken and that the cap on the transfer of personal leave at subclause 64.3c does not apply even where an Employer pays out accrued annual leave or long service leave upon termination in accordance with this Agreement.</p><p><strong>f.</strong> Calculation of continuous service shall be the same as for Long Service Leave under this Agreement.</p><p><strong>g.</strong> Reasonable Distance means a distance that has regard to the Employee’s original work location, current home address, capacity of the Employee to travel additional travelling time, effects on the personal circumstances of the affected Employee, including family commitments and responsibilities and other matters raised by the Employee, or assistance provided by their Employer.</p><p><strong>h.</strong> Redeployment period means a period of 13 weeks from the time the Employer notifies the Affected Employee in writing that consultation under clause 32.3b is complete and that the redeployment period has begun.</p><p><strong>i.</strong> Redundancy means the Employer no longer requires the Affected Employee’s job to be performed by anyone because of changes in the operational requirements of the Employer’s enterprise.</p><p><strong>j.</strong> Relocation means an Affected Employee required to move to a different Base Employment Campus on either a temporary or permanent basis.</p><p><strong>k.</strong> Salary maintenance means an amount representing the difference between what the Affected Employee was normally paid (including higher qualification allowance) prior to the Affected Employee’s role being made redundant and the amount paid in the Affected Employee’s new role following redeployment. ‘Normally paid’ means an Affected Employee’s current rate of pay including Higher Qualifications and any allowances and penalties (excluding overtime) averaged for the preceding 12 months worked, or the Affected Employee’s pay at the time of their role being made redundant, whichever is the greater.</p><p><strong>32.3</strong> Redeployment</p><p><strong>a.</strong> An Affected Employee whose role will be redundant will be considered for redeployment during the redeployment period.</p><p><strong>b.</strong> Employee to be advised in writing he Affected Employee must be advised in writing of:</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>(i)</strong> the date the Affected Employee’s role is to be redundant,</p><p><strong>(ii)</strong> details of the redeployment process,</p><p><strong>(iii)</strong> the reasonable support that will be provided in accordance with subclause 32.3c below, and</p><p><strong>(iv)</strong> the Affected Employee’s rights and obligations.</p><p><strong>c.</strong> Employer obligations The Employer will:</p><p><strong>(i)</strong> make every effort to redeploy the Affected Employee to a Comparable Role in terms of classification, grade and income, hours/roster and location, including appointing a case manager to provide the Affected Employee with support and assistance; and</p><p><strong>(ii)</strong> take into account the personal circumstances of the Affected Employee, including family commitments and responsibilities, medical restrictions limiting duties; and</p><p><strong>(iii)</strong> where the Employer is creating a new role/s substantially similar to the Affected Employee’s redundant role; give priority to the redeployment of Affected Employees to the new position/s before considering applicants that are not Affected Employees. Example: The Employer needs fewer Employees to do particular work and roles are being restructured to take this into account. The Employer will consider the Affected Employees for the new roles before other applicants.</p><p><strong>d.</strong> Employee obligations The Employee must actively participate in the redeployment process.</p><p><strong>e.</strong> Determining if a position is a Comparable Role In the event a dispute arises in relation to whether or not a position is a Comparable Role, discussion between the Employer and the Employee or the Employee’s representative will be held to try and resolve the dispute.</p><p><strong>f.</strong> Rejecting a comparable role</p><p><strong>(i)</strong> Where an Affected Employee rejects an offer of redeployment to a comparable role (as defined), the Affected Employee may be ineligible for a departure package referred to at subclause 32.6d.</p><p><strong>(ii)</strong> In such cases the Employer and the Employee or the Employee’s representative shall discuss the Affected Employee’s decision before the Employer decides its response.</p><p><strong>g.</strong> Temporary alternative duties An Affected Employee awaiting redeployment may agree to transfer to temporary alternative duties within the same campus, or where part of the Employee’s existing employment conditions, another campus. Such temporary duties will be in accordance with the Affected Employee’s skills, experience, clinical area and profession and will be paid at the Affected Employee’s current rate of pay.</p><p><strong>h.</strong> Support for redeployment For an available role to be considered a comparable role, the Employer must provide the reasonable support necessary for the Affected Employee to perform the role which may include:</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>(i)</strong> training relevant to the clinical area or environment of the role into which the Affected Employee is to be redeployed;</p><p><strong>(ii)</strong> a defined period of up to 12 weeks in which the Affected Employee works in a supernumerary capacity;</p><p><strong>(iii)</strong> support from educational staff in the clinical environment;</p><p><strong>(iv)</strong> a review at 12 weeks or earlier to determine what, if any, further training is required.</p><p><strong>i.</strong> Where no redeployment available If at any time during the redeployment period it is agreed that it is unlikely that the Affected Employee will be successfully redeployed, or the Employee elects to discontinue the redeployment process, the Affected Employee may accept a redundancy package. Where this occurs, the Affected Employee will be entitled to an additional payment of the lesser of 13 weeks or the remaining redeployment period.</p><p><strong>j.</strong> Non-Comparable Role</p><p><strong>(i)</strong> An Affected Employee may agree to be redeployed to a role that is not a Comparable Role.</p><p><strong>32.4</strong> Support to Affected Employees</p><p><strong>a.</strong> The Employer will provide Affected Employees whose position has been declared redundant with support and assistance which will include, where relevant:</p><p><strong>(i)</strong> counselling and support services;</p><p><strong>(ii)</strong> retraining,</p><p><strong>(iii)</strong> preparation of job applications;</p><p><strong>(iv)</strong> interview coaching;</p><p><strong>(v)</strong> time off to attend job interviews; and</p><p><strong>(vi)</strong> funding of independent financial advice for Employees eligible to receive a separation package. Other assistance may include, but is not limited to, career planning.</p><p><strong>b.</strong> Salary Maintenance</p><p><strong>(i)</strong> Entitlement to salary maintenance</p><p><strong>(ii)</strong> An Affected Employee who is successfully redeployed will be entitled to salary maintenance where the Affected Employee’s pay is reduced because the new role: <strong>(A)</strong> is a lower grade; or <strong>(B)</strong> involves working fewer hours; and/or <strong>(C)</strong> removes or reduces penalties, loadings and the like.</p><p><strong>(iii)</strong> An Affected Employee will have their salary maintenance payment paid as a fortnightly allowance, or as otherwise agreed.</p><p><strong>c.</strong> Period of salary maintenance Salary maintenance will be for a period of 52 weeks from the date the Affected Employee is redeployed except where the Affected Employee:</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p><strong>(i)</strong> accepts another position within the salary maintenance period, and</p><p><strong>(ii)</strong> is paid in the other position an amount equal to or greater than the role that was made redundant.</p><p><strong>d.</strong> Preservation of accrued leave An Affected Employee entitled to salary maintenance will have:</p><p><strong>(i)</strong> their long service leave and annual leave accruals preserved before redeployment. Specifically, the value of the leave immediately prior to redeployment will not be reduced as a result of redeployment; and</p><p><strong>(ii)</strong> their personal leave preserved in hours.</p><p><strong>32.5</strong> Relocation</p><p><strong>a.</strong> Employer to advise in writing of relocation As soon as practicable but no less than seven (7) days after a decision is made by the Employer to require an Employee to change their Base Employment Campus either temporarily (if agreed under subclause 32.3g) or permanently the Employer will advise the Affected Employee in writing of the decision, the proposed timing of the relocation and any other alternatives available to the Affected Employee. In addition, the Employer will:</p><p><strong>(i)</strong> ensure the relocation is a Reasonable Distance, unless otherwise agreed;</p><p><strong>(ii)</strong> ensure that the Affected Employee is provided with information on the new location’s amenities, layout and local operations prior to the relocation, and</p><p><strong>(iii)</strong> Consult with the Union regarding the content of such information.</p><p><strong>b.</strong> Entitlement to relocation allowance An Affected Employee is entitled to relocation allowance where permanent or temporary relocation results in additional cost to the Affected Employee for travel and / or other expenses.</p><p><strong>c.</strong> Employee to provide written estimate The Affected Employee must make written application to the Employer with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months.</p><p><strong>d.</strong> Payment</p><p><strong>(i)</strong> The Employer will pay the Affected Employee a relocation allowance up to $1900.00 based on the written estimate of the Affected Employee referred to at subclause 32.5c where the Employer accepts that estimate represents the additional cost to the Affected Employee. The allowance shall be paid as a lump sum.</p><p><strong>(ii)</strong> When considering the Affected Employee’s estimate, the Employer may have regard to the Reasonable Distance.</p><p><strong>(iii)</strong> In the event of a dispute about the Affected Employee’s estimate it will be resolved under <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> Dispute Resolution Procedure.</p><p><strong>e.</strong> Exceptions</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>An Affected Employee is not entitled to the relocation allowance if the site or campus to which the Affected Employee is being relocated is a location to which they can be expected to be deployed as part of their existing employment conditions save for a situation where because of the change the Employee has additional travelling beyond the existing conditions which will attract a reasonable pro rata relocation payment.</p><p><strong>f.</strong> Fixed term Employees not excluded An Affected Employee on a fixed term contract who is relocated will be covered by the terms of this clause for the duration of the fixed term contract.</p><p><strong>32.6</strong> Redundancy (Termination)</p><p><strong>a.</strong> The Victorian Government’s policy with respect to public sector redundancy and the entitlements (including pay) upon termination of employment as a result of redundancy are set out in the Public Sector Industrial Relations Policies 2015. The policy as at the time this Agreement comes into operation applies to Employees but does not form part of this Agreement.</p><p><strong>b.</strong> Redundancy will be used as a last resort. Employers will consider options of redeployment, relocation or other alternatives to mitigate redundancies as preferred options to making an Employee redundant.</p><p><strong>c.</strong> Where applicable Expressions of interest for voluntary departure will be pursued from non-affected Employees to facilitate redeployment of affected Employees.</p><p><strong>d.</strong> Where a position has been declared redundant and a Comparable Role is not available to redeploy the Affected Employee to, they or an Employee who has made an expression of interest in a departure package, shall be offered a departure package. The departure package shall be either a Voluntary Departure Package or a Targeted Separation Package as defined in The Victorian Government’s policy.</p><p><strong>32.7</strong> Exception to application of Victorian Government’s policy with respect to severance pay</p><p><strong>a.</strong> Where the Affected Employee’s Employer secures a comparable role (as defined) with another Employer covered by this Agreement, which:</p><p><strong>(i)</strong> is within a Reasonable Distance of the work site of the redundant position; and</p><p><strong>(ii)</strong> provides continuity of service; and</p><p><strong>(iii)</strong> where the comparable role results in a loss of income, salary maintenance at subclause 32.4b will apply; and</p><p><strong>(iv)</strong> where relevant, consistent with the financial and other support provided to an internal redeployee, the Employee will be considered successfully redeployed as though the employment was with the same Employer and no severance pay will apply.</p><p><strong>b.</strong> Where the Employee is a member of a defined benefit superannuation fund and has accepted a Targeted Separation Package, the Health Service shall notify the fund that the service of the Employee has been compulsorily terminated on account of retrenchment.</p><p><strong>c.</strong> Additional consultation, redundancy and associated entitlements provisions relating to Employees of some Employers are contained in <a href="/eba/ebas/mspp/schedules/8-royal-women-s-hospital-royal-children-s-hospital-general-emp.html">Schedule 8</a> and</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>3453-8976-3100v1PART 4: EMPLOYMENT RELATIONSHIP AND RELATED ARRANGEMENTS</p><p>Plain language terms: redundancy pay, retrenchment.</p>',110)])])}const g=t(r,[["render",s]]);export{h as __pageData,g as default};
